void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var f = vector<ll>(n + 1);      // 子树不进行操作的答案
	var dp = vector<ll>(n + 1);     // 子树进行操作的答案
	var suma = vector<ll>(n + 1);   // 子树权值和
	var mxdep = vector<ll>(n + 1);  // 子树最大深度
	var dfs = [&](var dfs, int now, int fa, int dep)->void {
		suma[now] = a[now];
		mxdep[now] = dep;

		var sons = vector<int>();
		for (int to : g[now]) {
			if (to == fa)continue;
			sons.pb(to);
			dfs(dfs, to, now, dep + 1);
			suma[now] += suma[to];
			f[now] += f[to] + suma[to];
			mxdep[now] = max(mxdep[now], mxdep[to]);
		}

		// 直接继承 to 子树的 dp
		fa(i, 0, vs(sons)) {
			int to = sons[i];
			dp[now] = max(dp[now], f[now] - f[to] + dp[to]);
		}

		// 前后缀求最大 suma
		var suf = vector<ll>(vs(sons) + 2);
		fb(i, vs(sons), 0)
			suf[i] = max(suf[i + 1], suma[sons[i]]);

		ll pre = 0;
		fa(i, 0, vs(sons)) {
			int to = sons[i];
			ll now_mx_suma = max(pre, suf[i + 1]); // 除了 to 以外，最大的 suma
			ll res = f[now] + now_mx_suma * (mxdep[to] - dep); // 最大的 suma 换根到 to 子树下面
			dp[now] = max(dp[now], res);
			pre = max(pre, suma[to]);
		}
		};
	dfs(dfs, 1, 0, 0);

	fa(i, 1, n)cout << dp[i] << ' ';
	cout << endl;
	return;
}
